def test_close_account_nonzero_balance_without_sweep_fails():
    acct_id = <fixture_create_account>(balance=150.50)
    auth_token = <fixture_auth_token>
    resp = requests.post(
        f"{BASE_URL}/accounts/{acct_id}/close",
        headers={"Authorization": f"Bearer {auth_token}"}
    )
    assert resp.status_code == 409
    assert resp.json()["error_code"] == "BALANCE_NOT_ZERO"
    check_resp = requests.get(
        f"{BASE_URL}/accounts/{acct_id}",
        headers={"Authorization": f"Bearer {auth_token}"}
    )
    assert check_resp.json()["state"] == "open"
    assert check_resp.json()["balance"] == 150.50

def test_close_account_boundary_near_zero_balance_succeeds():
    acct_id = <fixture_create_account>(balance=0.01)
    auth_token = <fixture_auth_token>
    resp = requests.post(
        f"{BASE_URL}/accounts/{acct_id}/close",
        headers={"Authorization": f"Bearer {auth_token}"}
    )
    assert resp.status_code == 409
    assert resp.json()["error_code"] == "BALANCE_NOT_ZERO"
    sweep_acct = <fixture_create_account>(owner=<caller_id>)
    resp_sweep = requests.post(
        f"{BASE_URL}/accounts/{acct_id}/close",
        json={"sweep_target": sweep_acct},
        headers={"Authorization": f"Bearer {auth_token}"}
    )
    assert resp_sweep.status_code == 200

def test_close_account_unauthorized_caller_fails():
    owner_id = <fixture_create_user>
    other_id = <fixture_create_user>
    acct_id = <fixture_create_account>(owner=owner_id, balance=0.0)
    other_token = <fixture_auth_token>(user_id=other_id)
    resp = requests.post(
        f"{BASE_URL}/accounts/{acct_id}/close",
        headers={"Authorization": f"Bearer {other_token}"}
    )
    assert resp.status_code in [401, 403]
    check = requests.get(
        f"{BASE_URL}/accounts/{acct_id}",
        headers={"Authorization": f"Bearer <owner_token>"}
    )
    assert check.json()["state"] == "open"
